import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common'; // Contient NgFor ou la syntaxe @for

@Component({
  selector: 'app-job-manage',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './job-manage.component.html',
  styleUrls: ['./job-manage.component.css']
})
export class JobManageComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  // Tableau qui va recevoir les vraies annonces du backend
  jobsList: any[] = [];
  isLoading: boolean = true;

  ngOnInit() {
    this.fetchRecruiterJobs();
  }

  fetchRecruiterJobs() {
    const targetUrl = 'http://localhost:3000/api/recruiter/jobs/list';
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'GET',
      headers: {
        'Authorization': token ? `Bearer ${token}` : ''
      }
    })
    .then(async res => {
      if (!res.ok) throw new Error("Impossible de récupérer les annonces.");
      return res.json();
    })
    .then(data => {
      // 🌟 On stocke les données reçues (vérifiez si votre backend renvoie directement un tableau ou un objet du type data.jobs)
      this.jobsList = Array.isArray(data) ? data : (data.jobs || []);
      this.isLoading = false;
      this.cdr.detectChanges(); // Force le rendu visuel sur l'interface
    })
    .catch(err => {
      console.error("Erreur récupération jobs:", err);
      this.isLoading = false;
      this.cdr.detectChanges();
    });
  }
}
<table class="jobs-table">
  <thead>
    <tr>
      <th>Intitulé du Poste</th>
      <th>Type de Contrat</th>
      <th>Localisation</th>
      <th>Candidatures Reçues</th>
      <th>Statut</th>
    </tr>
  </thead>
  <tbody>
    <!-- 🔄 Affichage d'un indicateur de chargement si l'API répond lentement -->
    @if (isLoading) {
      <tr>
        <td colspan="5" style="text-align: center; padding: 20px; color: #64748b;">
          Chargement de vos annonces en cours...
        </td>
      </tr>
    }

    <!-- 🚫 Cas où le recruteur n'a encore publié aucune annonce -->
    @if (!isLoading && jobsList.length === 0) {
      <tr>
        <td colspan="5" style="text-align: center; padding: 30px; color: #64748b;">
          <i class="bi bi-folder-x" style="font-size: 24px; display: block; margin-bottom: 8px;"></i>
          Aucune annonce publiée pour le moment.
        </td>
      </tr>
    }

    <!-- 🚀 BOUCLE DYNAMIQUE SUR LES VRAIES ANNONCES MYSQL -->
    @for (job of jobsList; track job.id) {
      <tr>
        <!-- Intitulé -->
        <td style="font-weight: 600; color: #0f172a;">{{ job.title }}</td>
        
        <!-- Type de contrat -->
        <td>{{ job.contract_type }}</td>
        
        <!-- Localisation -->
        <td>{{ job.location }}</td>
        
        <!-- Candidatures Reçues (Affiche 0 par défaut si non défini dans la jointure SQL) -->
        <td>
          <i class="bi bi-people-fill" style="color: #64748b; margin-right: 5px;"></i>
          {{ job.application_count || 0 }} profils
        </td>
        
        <!-- Statut Dynamique (Badge Vert si actif/disponible) -->
        <td>
          <span class="badge" [ngClass]="job.status === 'disponible' || job.status === 'Actif' ? 'badge-active' : 'badge-inactive'">
            {{ job.status === 'disponible' ? 'Actif' : job.status }}
          </span>
        </td>
      </tr>
    }
  </tbody>
</table>
